  public void UpdateAssignment(CivRosterStateEvent state)
  {
    if (!state.Enabled)
    {
      this.AssignmentTeam.Text = Loc.GetString("civ-lobby-gui-tdm-not-selected");
      this.AssignmentTeam.FontColorOverride = new Color?(CivLobbyGui.AssignmentTeamMuted);
      this.AssignmentRole.Text = Loc.GetString("civ-lobby-gui-pick-mode");
      this.AssignmentCommander.Text = string.Empty;
    }
    else
    {
      CivRosterPlayerEntry rosterPlayerEntry = state.Players.FirstOrDefault<CivRosterPlayerEntry>((Func<CivRosterPlayerEntry, bool>) (p => p.IsSelected));
      int? nullable = (int?) rosterPlayerEntry?.TeamId;
      CivRosterTeamEntry civRosterTeamEntry1;
      if (nullable.HasValue)
      {
        int tid = nullable.GetValueOrDefault();
        civRosterTeamEntry1 = state.Teams.FirstOrDefault<CivRosterTeamEntry>((Func<CivRosterTeamEntry, bool>) (t => t.TeamId == tid));
      }
      else
        civRosterTeamEntry1 = (CivRosterTeamEntry) null;
      CivRosterTeamEntry civRosterTeamEntry2 = civRosterTeamEntry1;
      if (rosterPlayerEntry == null || civRosterTeamEntry2 == null)
      {
        this.AssignmentTeam.Text = Loc.GetString("civ-lobby-gui-assignment-unassigned");
        this.AssignmentTeam.FontColorOverride = new Color?(CivLobbyGui.AssignmentTeamMuted);
        this.AssignmentRole.Text = Loc.GetString("civ-lobby-gui-assignment-pick");
        this.AssignmentCommander.Text = string.Empty;
      }
      else
      {
        this.AssignmentTeam.Text = civRosterTeamEntry2.TeamName.ToUpperInvariant();
        this.AssignmentTeam.FontColorOverride = new Color?(civRosterTeamEntry2.TeamId == 1 ? CivLobbyGui.AssignmentTeam1 : CivLobbyGui.AssignmentTeam2);
        string displayName = CivTdmClassHelper.GetDisplayName(rosterPlayerEntry.Class);
        Label assignmentRole = this.AssignmentRole;
        nullable = rosterPlayerEntry.SquadId;
        string str;
        if (!nullable.HasValue)
          str = Loc.GetString("civ-lobby-gui-assignment-no-squad", new (string, object)[1]
          {
            ("class", (object) displayName)
          });
        else
          str = Loc.GetString("civ-lobby-gui-assignment-squad", new (string, object)[2]
          {
            ("class", (object) displayName),
            ("squad", (object) rosterPlayerEntry.SquadId)
          });
        assignmentRole.Text = str;
        if (string.IsNullOrWhiteSpace(civRosterTeamEntry2.CommanderName))
        {
          this.AssignmentCommander.Text = Loc.GetString("civ-lobby-gui-commander-none");
          this.AssignmentCommander.FontColorOverride = new Color?(CivLobbyGui.AssignmentCommanderMissing);
        }
        else
        {
          this.AssignmentCommander.Text = Loc.GetString("civ-lobby-gui-commander", new (string, object)[1]
          {
            ("name", (object) civRosterTeamEntry2.CommanderName)
          });
          this.AssignmentCommander.FontColorOverride = new Color?(CivLobbyGui.AssignmentCommanderActive);
        }
      }
    }
  }

